  return {
    fullPage: true,
    mask: [page.locator('.develop')],
  };
}

/**
 * ヘルパー関数: スクリーンショットを撮影
 */
async function takeScreenshot(page: Page): Promise<void> {
  await expect(page).toHaveScreenshot(getScreenshotOptions(page));
}

/**
 * ヘルパー関数: モバイルかどうかを判定
 */
function isMobileDevice(testInfo: TestInfo): boolean {
  return testInfo.project.name.includes('Mobile Chrome');
}

