  });

  test('/teams/[team_id]/sessions - セッション管理画面とモーダル', async (
    { page },
    testInfo,
  ) => {
    const isMobile = isMobileDevice(testInfo);
    await page.goto(`/teams/${TEST_DATA.TEAM_ID}/sessions`);
