    await takeScreenshot(page);
  });
});

content.text:
メニューが開くのを待つには、以下の方法があります：

## 推奨方法

メニュー要素が表示されるまで明示的に待機する方法が最も安全です：

```typescript
await page.getByRole('table').getByRole('button').first().click();
// メニュー項目が表示されるまで待機
await page.getByRole('menuitem').first().waitFor({ state: 'visible' });
```

または、特定のメニュー項目を待つ場合：

```typescript
await page.getByRole('table').getByRole('button').first().click();
// 特定のメニュー項目が表示されるまで待機
await page.getByRole('menuitem', { name: 'Delete' }).waitFor({ state: 'visible' });
```

## その他の方法

### 1. 固定遅延（非推奨）
```typescript
await page.getByRole('table').getByRole('button').first().click();
await page.waitForTimeout(300); // 300ms待機
```

### 2. ネットワーク待機
```typescript
await page.getByRole('table').getByRole('button').first().click();
await page.waitForLoadState('networkidle');
```

### 3. アニメーション完了待機
```typescript
await page.getByRole('table').getByRole('button').first().click();
await page.waitForSelector('[role="menu"]', { state: 'visible' });
```

## 実装例

`openSessionActionMenu` 関数を修正する場合：

```typescript
async function openSessionActionMenu(
  page: Page,
  isMobile: boolean,
): Promise<void> {
  if (isMobile) {
    await page
      .locator('.MuiGrid2-root')
      .locator('.MuiGrid2-root')
      .locator('.MuiPaper-root')
      .locator('.MuiBox-root')
      .getByRole('button')
      .first()
      .click();
  } else {
    await page.getByRole('table').getByRole('button').first().click();
  }
  // メニューが開くまで待機
  await page.getByRole('menuitem').first().waitFor({ state: 'visible' });
}
```

この方法を適用しますか？
